nodes.inputScript:
// Alias the implementation plan into a stable global key for downstream agents. If we're
// invoked as a subflow after impl-plan-flow, the plan is already in workflow.currentPlan; if
// we're invoked standalone, the plan arrives as the input artifact.
var plan = (global && workflow.currentPlan) ? workflow.currentPlan : (input && input.text) ? input.text : '';
if (plan) { setWorkflow('implPlan', plan); }

// Extract a PRD title for the feature-branch helper. Look in workflow.prd's first heading or
// in workflow.prdTitle if a parent workflow already populated it. Falls through silently when
// neither is present — branch_name() degrades to `branch-<8hex>`.
if (!(global && workflow.prdTitle)) {
  var prdSource = (global && workflow.prd) ? String(workflow.prd) : '';
  var match = prdSource.match(/^\s*#\s+(.+?)\s*$/m);
  if (match) { setWorkflow('prdTitle', match[1]); }
}

nodes.outputScript:
var ts = workflow.taskStatus;
var tasks = (ts && ts.tasks) ? ts.tasks : [];
var hasBlockedOrDeferred = false;
for (var i = 0; i < tasks.length; i++) {
  if (tasks[i].status === 'blocked' || tasks[i].status === 'deferred') {
    hasBlockedOrDeferred = true;
    break;
  }
}
setNodePath(hasBlockedOrDeferred ? 'HasBlocked' : 'AllGood');

